# -*- coding: utf-8 -*-
"""
deploy_tushare_phase2.py — Phase 2:Tushare 补 FCF (v1.0.0)
==========================================================
装 tushare_data.py + 升级 line_items_china.py 到 v3(baostock 反推 + tushare 真值叠加)。
**无 token 完全惰性**:行为与当前(纯 baostock,FCF=None)一致;配 token 后 FCF 自动生效。

前置(获得真 FCF 所需,可后补):
  1. tushare.pro 注册,攒 ≥2000 积分(cashflow 接口门槛)
  2. poetry add tushare
  3. 设环境变量: setx AIHF_TUSHARE_TOKEN "你的token"  (setx 后重开终端)

用法:
    cd E:\\AI-tool\\Stock\\ai-hedge-fund
    poetry run python deploy_tushare_phase2.py
"""
import base64, os, sys, shutil, datetime, traceback
_DEFAULT=r"E:\AI-tool\Stock\ai-hedge-fund"
ROOT=sys.argv[1] if len(sys.argv)>1 else (os.getcwd() if os.path.isdir(os.path.join(os.getcwd(),"src","tools")) else _DEFAULT)
TOOLS=os.path.join(ROOT,"src","tools")
if not os.path.isdir(TOOLS): print("[FATAL] 找不到 src/tools"); sys.exit(2)
print("ROOT =",ROOT,("OK" if os.path.normpath(ROOT)==os.path.normpath(os.getcwd()) else "⚠️与CWD不同"))
BACKUP=os.path.join(ROOT,"_aihf_backup_"+datetime.datetime.now().strftime("%Y%m%d_%H%M%S"))
os.makedirs(BACKUP,exist_ok=True)

TD_B64=""; LIC_B64=""
print("\n==== 1) 部署文件 ====")
p=os.path.join(TOOLS,"tushare_data.py")
open(p,"w",encoding="utf-8",newline="\n").write(base64.b64decode(TD_B64).decode("utf-8"))
print("  写入 tushare_data.py (%d bytes)"%os.path.getsize(p))
lic=os.path.join(TOOLS,"line_items_china.py")
if os.path.isfile(lic):
    shutil.copy2(lic,os.path.join(BACKUP,"line_items_china.py")); print("  备份 line_items_china.py")
open(lic,"w",encoding="utf-8",newline="\n").write(base64.b64decode(LIC_B64).decode("utf-8"))
print("  写入 line_items_china.py v3 (%d bytes)"%os.path.getsize(lic))

print("\n==== 2) 验证 ====")
sys.path.insert(0,ROOT)
try:
    from src.tools import tushare_data as td
    print("tushare 包已装:", td._HAVE_TS)
    print("AIHF_TUSHARE_TOKEN 已配:", bool(os.environ.get("AIHF_TUSHARE_TOKEN") or os.environ.get("TUSHARE_TOKEN")))
    print("tushare available:", td.available())
    from src.tools.line_items_china import search_line_items_china
    items=search_line_items_china("600519",["revenue","net_income","free_cash_flow","capital_expenditure"],"2026-06-22",limit=2)
    if items:
        it=items[0]
        print("line_items(600519): rev=%.1f亿 net=%.1f亿 fcf=%s capex=%s" % (
            (it.revenue or 0)/1e8,(it.net_income or 0)/1e8,it.free_cash_flow,it.capital_expenditure))
        if td.available() and it.free_cash_flow is not None:
            print(">>> ✅ Tushare 已生效:FCF=%.1f亿 (buffett owner-earnings 回归) <<<" % (it.free_cash_flow/1e8))
        elif not td.available():
            print(">>> ℹ️ 未配 token,FCF=None(纯 baostock,行为不变)。配好 token 后 FCF 自动出现 <<<")
        else:
            print(">>> ⚠️ token 已配但 FCF 仍 None:可能积分<2000 或此票 tushare 无现金流。换地基逻辑无影响 <<<")
    else:
        print("line_items 空(检查 baostock)")
except Exception:
    print("[验证异常]\n"+traceback.format_exc())
print("\n备份:",BACKUP,"\n==== 完成 ==== 把输出贴回")
